  <!-- ══════════════════════════════════════
       JAVASCRIPT
  ══════════════════════════════════════ -->
  <script>
    // ─────────────────────────────────────────────────────────────
    // The regex used here is a reasonable, practical pattern.
    // It is intentionally NOT the full RFC 5322 pattern because
    // that would be 6 000+ chars and still incomplete.
    // This one covers ~99% of real-world addresses people type.
    // ─────────────────────────────────────────────────────────────
    const EMAIL_REGEX = /^(?!\.)(?!.*\.\.)([a-zA-Z0-9!#$%&'*+/=?^_`{|}~-]+(?:\.[a-zA-Z0-9!#$%&'*+/=?^_`{|}~-]+)*)@(?:(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+[a-zA-Z]{2,})$/;

    // Display the regex string
    document.getElementById('regexDisplay').textContent = EMAIL_REGEX.toString();

    // ── Test cases ─────────────────────────────────────────────
    const TEST_CASES = [
      // Should pass
      { addr: 'user@example.com',           label: 'valid',   cls: 'should-pass' },
      { addr: 'first.last@sub.domain.io',   label: 'valid',   cls: 'should-pass' },
      { addr: 'user+tag@gmail.com',         label: 'valid',   cls: 'should-pass' },
      { addr: 'x@y.co',                     label: 'valid',   cls: 'should-pass' },
      { addr: '123@numbers.net',            label: 'valid',   cls: 'should-pass' },
      { addr: 'a.b+c_d@e-f.org',           label: 'valid',   cls: 'should-pass' },

      // Should fail
      { addr: 'notanemail',                  label: 'invalid', cls: 'should-fail' },
      { addr: '@nodomain.com',               label: 'invalid', cls: 'should-fail' },
      { addr: 'double@@at.com',             label: 'invalid', cls: 'should-fail' },
      { addr: 'space here@x.com',           label: 'invalid', cls: 'should-fail' },
      { addr: '.leadingdot@x.com',          label: 'invalid', cls: 'should-fail' },
      { addr: 'double..dot@x.com',          label: 'invalid', cls: 'should-fail' },

      // Tricky — RFC valid but regex rejects (shows regex limits!)
      { addr: '"quoted string"@example.com', label: 'RFC valid ✓ regex ✗', cls: 'tricky' },
      { addr: 'user@[192.168.1.1]',          label: 'RFC valid ✓ regex ✗', cls: 'tricky' },
    ];

    // Build test grid
    const grid = document.getElementById('testGrid');
    TEST_CASES.forEach(tc => {
      const item = document.createElement('div');
      item.className = 'test-item';
      item.innerHTML = `
        <span class="addr">${escHtml(tc.addr)}</span>
        <span class="badge ${tc.cls}">${tc.label}</span>
      `;
      item.addEventListener('click', () => {
        const input = document.getElementById('emailInput');
        input.value = tc.addr;
        validate(tc.addr);
        input.focus();
      });
      grid.appendChild(item);
    });

    // ── Validation logic ────────────────────────────────────────
    const input       = document.getElementById('emailInput');
    const feedbackMsg = document.getElementById('feedbackMsg');
    const statusIcon  = document.getElementById('statusIcon');
    const strengthBar = document.getElementById('strengthBar');

    function validate(value) {
      if (value.length === 0) {
        setIdle();
        return;
      }

      const isValid = EMAIL_REGEX.test(value);

      if (isValid) {
        setValid(value);
      } else {
        setInvalid(value);
      }
    }

    function setIdle() {
      input.className = 'idle';
      statusIcon.textContent = '';
      feedbackMsg.className = 'feedback tip';
      feedbackMsg.textContent = 'Start typing to see real-time validation…';
      setBar(0, '#334155');
    }

    function setValid(value) {
      input.className = 'valid';
      statusIcon.textContent = '✅';
      feedbackMsg.className = 'feedback ok';

      // Compute a rough "confidence" score
      const score = computeScore(value);
      feedbackMsg.textContent = `Looks valid! (regex confidence: ${score}%) — DNS & SMTP not checked.`;
      setBar(score, '#22c55e');
    }

    function setInvalid(value) {
      input.className = 'invalid';
      statusIcon.textContent = '❌';
      feedbackMsg.className = 'feedback err';
      feedbackMsg.textContent = diagnose(value);
      setBar(10, '#ef4444');
    }

    function setBar(pct, color) {
      strengthBar.style.width   = pct + '%';
      strengthBar.style.background = color;
    }

    // Rough heuristic confidence score (not security-relevant)
    function computeScore(email) {
      let score = 60;
      const [local, domain] = email.split('@');
      if (domain && domain.split('.').pop().length >= 2) score += 10;
      if (domain && domain.includes('.')) score += 10;
      if (local.length >= 3) score += 5;
      if (!email.includes('+')) score += 5; // no subaddressing (slightly more "normal")
      if (domain && domain.length >= 4) score += 5;
      if (/\.(com|org|net|io|edu|gov)$/.test(domain)) score += 5;
      return Math.min(score, 95); // never claim 100% — honest about limits
    }

    // Friendly diagnosis messages
    function diagnose(value) {
      if (!value.includes('@'))          return 'Missing "@" symbol.';
      const parts = value.split('@');
      if (parts.length > 2)              return 'Multiple "@" symbols found.';
      const [local, domain] = parts;
      if (!local)                        return 'Local part (before @) is empty.';
      if (!domain)                       return 'Domain part (after @) is empty.';
      if (local.startsWith('.'))         return 'Local part cannot start with a dot.';
      if (local.endsWith('.'))           return 'Local part cannot end with a dot.';
      if (/\.{2,}/.test(local))          return 'Local part has consecutive dots.';
      if (!domain.includes('.'))         return 'Domain must contain at least one dot.';
      if (domain.startsWith('.'))        return 'Domain cannot start with a dot.';
      if (domain.endsWith('.'))          return 'Domain cannot end with a dot.';
      if (/\s/.test(value))             return 'Spaces are not allowed (use quotes for RFC compliance).';
      const tld = domain.split('.').pop();
      if (tld.length < 2)               return 'Top-level domain is too short.';
      return 'Format does not match expected email pattern.';
    }

    // HTML escape helper
    function escHtml(str) {
      return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }

    // ── Event listeners ─────────────────────────────────────────
    input.addEventListener('input',  e => validate(e.target.value.trim()));
    input.addEventListener('blur',   e => { if (e.target.value) validate(e.target.value.trim()); });
    input.addEventListener('paste',  e => {
      // slight delay so the pasted value is in the input
      setTimeout(() => validate(input.value.trim()), 0);
    });
  </script>
</body>
</html>
```

---

## What This File Contains

| Section | What it does |
|---|---|
| **Live validator** | Real-time green/red border, icon, feedback message, and a confidence bar as you type |
| **Regex display** | Shows the exact pattern being used so nothing is hidden |
| **Clickable test cases** | 14 examples including *tricky RFC-valid addresses* the regex rejects, proving the point visually |
| **Limitations card** | 7 specific, sourced reasons regex fails — quoted locals, comments, IP literals, IDN, TLD staleness, DNS, SMTP |
| **Alternatives card** | Four progressive tiers from zero-code HTML5 up to confirmation email tokens |

## Key Design Decisions

- **Confidence bar never reaches 100%** — intentionally honest; `computeScore()` caps at 95
- **Diagnosis messages are specific** — tells the user *why* it failed, not just that it did
- **"Tricky" test cases are labelled** — `"quoted string"@example.com` is RFC 5321 valid but the regex rejects it, which is the entire lesson made interactive
- **No frameworks, no network requests** — fully self-contained and offline-capable

