<script>
    // ── Configuration ──────────────────────────────────────────────────────────

    // A pragmatic regex: not RFC-complete, but a solid practical filter.
    // Breakdown:
    //   ^[^\s@]+      → local part: one or more non-whitespace, non-@ chars
    //   @             → literal @
    //   [^\s@]+       → domain label(s): one or more non-whitespace, non-@ chars
    //   \.            → literal dot before TLD
    //   [^\s@]{2,}$   → TLD: at least 2 non-whitespace, non-@ chars
    const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

    const EXAMPLES = [
        { address: 'user@example.com',          valid: true  },
        { address: 'firstname.lastname@company.org', valid: true  },
        { address: 'user+tag@subdomain.example.co.uk', valid: true },
        { address: 'user123@my-domain.io',      valid: true  },
        { address: 'contact@example.photography', valid: true },
        { address: 'plainaddress',              valid: false },
        { address: '@nodomain.com',             valid: false },
        { address: 'missing@dotcom',            valid: false },
        { address: 'two@@at.com',               valid: false },
        { address: 'spaces in@email.com',       valid: false },
        { address: 'user@.com',                 valid: false },
        { address: '',                          valid: false },
    ];

    // ── DOM refs ───────────────────────────────────────────────────────────────
    const input      = document.getElementById('emailInput');
    const statusIcon = document.getElementById('statusIcon');
    const statusMsg  = document.getElementById('statusMessage');
    const partLocal  = document.getElementById('partLocal');
    const partDomain = document.getElementById('partDomain');
    const partTLD    = document.getElementById('partTLD');
    const exGrid     = document.getElementById('exampleGrid');

    // ── Validation logic ───────────────────────────────────────────────────────
    function validate(email) {
        if (!email) return null;               // null = empty
        return EMAIL_REGEX.test(email);        // true = valid, false = invalid
    }

    function parseEmail(email) {
        const atIdx = email.lastIndexOf('@');
        if (atIdx === -1) return { local: email, domain: '', tld: '' };

        const local  = email.slice(0, atIdx);
        const rest   = email.slice(atIdx + 1);
        const dotIdx = rest.lastIndexOf('.');
        const domain = dotIdx === -1 ? rest : rest.slice(0, dotIdx);
        const tld    = dotIdx === -1 ? ''   : rest.slice(dotIdx + 1);

        return { local, domain, tld };
    }

    function updateUI(email) {
        const result = validate(email);
        const { local, domain, tld } = parseEmail(email);

        // Clear classes
        input.classList.remove('valid', 'invalid');

        if (result === null) {
            // Empty
            statusIcon.textContent = '';
            statusMsg.textContent  = 'Start typing to validate your email address…';
            statusMsg.className    = 'status-message neutral';
            setPartStyle('neutral');
            partLocal.textContent  = '—';
            partDomain.textContent = '—';
            partTLD.textContent    = '—';
            return;
        }

        if (result) {
            input.classList.add('valid');
            statusIcon.textContent = '✅';
            statusMsg.textContent  = '✓ Format looks valid (regex check passed)';
            statusMsg.className    = 'status-message valid';
            setPartStyle('valid');
        } else {
            input.classList.add('invalid');
            statusIcon.textContent = '❌';
            statusMsg.textContent  = '✗ Invalid format — check for missing @, domain, or TLD';
            statusMsg.className    = 'status-message invalid';
            setPartStyle('invalid');
        }

        partLocal.textContent  = local  || '—';
        partDomain.textContent = domain || '—';
        partTLD.textContent    = tld    || '—';
    }

    function setPartStyle(state) {
        [partLocal, partDomain, partTLD].forEach(el => {
            el.classList.remove('highlight-valid', 'highlight-invalid', 'highlight-neutral');
            el.classList.add(`highlight-${state}`);
        });
    }

    // ── Event listeners ────────────────────────────────────────────────────────
    input.addEventListener('input',  () => updateUI(input.value.trim()));
    input.addEventListener('paste',  () => setTimeout(() => updateUI(input.value.trim()), 0));

    // ── Build example chips ────────────────────────────────────────────────────
    EXAMPLES.forEach(ex => {
        if (!ex.address) return;                // skip the empty string example
        const chip = document.createElement('button');
        chip.className = `example-chip ${ex.valid ? 'valid-example' : 'invalid-example'}`;
        chip.innerHTML = `<span class="chip-icon">${ex.valid ? '✓' : '✗'}</span>${ex.address}`;
        chip.title     = ex.valid ? 'Click to test — should pass' : 'Click to test — should fail';
        chip.addEventListener('click', () => {
            input.value = ex.address;
            updateUI(ex.address);
            input.focus();
        });
        exGrid.appendChild(chip);
    });
</script>
</body>
</html>
