  <script>
    // ─────────────────────────────────────────────
    //  The regex we use — a pragmatic "good enough"
    //  pattern for everyday UX feedback only.
    // ─────────────────────────────────────────────
    const EMAIL_REGEX = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*\.[a-zA-Z]{2,}$/;

    // Display the regex string
    document.getElementById('regexDisplay').textContent = EMAIL_REGEX.toString();

    // ── Test cases ──────────────────────────────
    const testCases = [
      { email: 'user@example.com',          pass: true  },
      { email: 'firstname.lastname@co.uk',  pass: true  },
      { email: 'user+tag@sub.domain.io',    pass: true  },
      { email: 'x@y.photography',           pass: true  },
      { email: 'plainaddress',              pass: false },
      { email: '@no-local.com',             pass: false },
      { email: 'missing@dot',              pass: false },
      { email: 'double@@domain.com',        pass: false },
      // Technically RFC-valid but likely rejected by our regex:
      { email: '"quoted"@example.com',      pass: true  },
      { email: 'user@[192.168.1.1]',        pass: false },
    ];

    const grid = document.getElementById('testGrid');
    testCases.forEach(({ email, pass }) => {
      const item = document.createElement('div');
      item.className = 'test-item';
      item.title = `Click to test: ${email}`;
      item.innerHTML = `
        <span class="dot ${pass ? 'should-pass' : 'should-fail'}"></span>
        <div>
          <div style="word-break:break-all">${email}</div>
          <div class="test-label">${pass ? 'should pass' : 'should fail'}</div>
        </div>`;
      item.addEventListener('click', () => {
        emailInput.value = email;
        validate(email);
        emailInput.focus();
      });
      grid.appendChild(item);
    });

    // ── Live Validation ──────────────────────────
    const emailInput  = document.getElementById('emailInput');
    const feedback    = document.getElementById('feedback');
    const statusIcon  = document.getElementById('statusIcon');

    function validate(value) {
      if (value === '') {
        emailInput.classList.remove('valid', 'invalid');
        statusIcon.classList.remove('show');
        statusIcon.textContent = '';
        feedback.className = 'neutral';
        feedback.textContent = 'Start typing to validate…';
        return;
      }

      const isValid = EMAIL_REGEX.test(value);

      emailInput.classList.toggle('valid',   isValid);
      emailInput.classList.toggle('invalid', !isValid);

      statusIcon.textContent  = isValid ? '✅' : '❌';
      statusIcon.classList.add('show');

      if (isValid) {
        feedback.className   = 'valid';
        feedback.textContent = '✓ Looks like a valid email format (regex check only)';
      } else {
        feedback.className   = 'invalid';
        feedback.textContent = diagnose(value);
      }
    }

    function diagnose(v) {
      if (!v.includes('@'))          return '✗ Missing "@" symbol';
      const [local, ...rest]  = v.split('@');
      const domain            = rest.join('@');
      if (!local)                    return '✗ Local part (before @) is empty';
      if (rest.length > 1)           return '✗ Multiple "@" symbols found';
      if (!domain)                   return '✗ Domain (after @) is empty';
      if (!domain.includes('.'))     return '✗ Domain has no dot — missing TLD?';
      if (domain.startsWith('.'))    return '✗ Domain cannot start with a dot';
      if (domain.endsWith('.'))      return '✗ Domain cannot end with a dot';
      if (/\.{2,}/.test(domain))     return '✗ Domain contains consecutive dots';
      const tld = domain.split('.').pop();
      if (tld.length < 2)            return '✗ TLD must be at least 2 characters';
      return '✗ Invalid format — check for illegal characters or structure';
    }

    emailInput.addEventListener('input', e => validate(e.target.value.trim()));
  </script>
</body>
</html>
```

