from email_validator import validate_email, EmailNotValidError

try:
    info = validate_email("user@example.com", check_deliverability=True)
    print(info.normalized)  # normalized form
except EmailNotValidError as e:
    print(str(e))
# This actually checks DNS MX records too
```

**PHP**
```php
// Built into PHP — uses a real parser, not regex
$email = "user@example.com";
if (filter_var($email, FILTER_VALIDATE_EMAIL)) {
    // Still only syntax — but far more RFC-correct than DIY regex
}
```

**Go**
```go
// net/mail from stdlib — RFC 5322 compliant parser
import "net/mail"

addr, err := mail.ParseAddress("User <user@example.com>")
if err == nil {
    fmt.Println(addr.Address) // user@example.com
}
```

---

### 3. DNS / MX Record Verification

```js
// Node.js — check that the domain can actually receive mail
import dns from 'dns/promises';

async function hasMXRecord(email) {
  const domain = email.split('@')[1];
  try {
    const records = await dns.resolveMx(domain);
    return records.length > 0;
  } catch {
    return false; // domain doesn't exist or has no MX
  }
}

await hasMXRecord('user@gmail.com');      // true
await hasMXRecord('user@fakexyz999.com'); // false
```

This catches:
- Domains that don't exist
- Domains with no mail server configured
- Typos like `gmial.com` or `yahooo.com`

---

### 4. Typo Suggestion (Better UX Than Rejection)

```js
// npm install mailcheck
import Mailcheck from 'mailcheck';

Mailcheck.run({
  email: 'user@gmial.com',
  suggested: (suggestion) => {
    console.log(suggestion.full); // "user@gmail.com"
    // Show: "Did you mean user@gmail.com?"
  }
});
```

This is **better UX** than a red border. Users make typos. Help them fix it rather than blocking them.

